import React, { useEffect, useState } from "react";
import api from "../api";
import { motion } from "framer-motion";

export default function TodayDashboard() {
  const [todayFoods, setTodayFoods] = useState([]);

  useEffect(() => {
    const fetchDashboard = async () => {
      try {
        const res = await api.get("/foods/today");
        setTodayFoods(res.data);
      } catch (err) {
        console.error("Fetch today foods error:", err);
      }
    };
    fetchDashboard();
  }, []);

  const outOfStockEvent = async (id) => {
    try {
      await api.put(`/foods/manage/${id}`);
      alert("This item is out-of-stock");

      // Update local state to disable the button
      setTodayFoods((prev) =>
        prev.map((food) =>
          food._id === id ? { ...food, outofstack: true } : food
        )
      );
    } catch (err) {
      console.error("Out-of-stock update error:", err);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-100 to-slate-200 p-6">
      <div className="mx-auto">
        <h1 className="text-3xl font-bold mb-8 text-center text-slate-800">
          Today Menu
        </h1>

        <div className="flex flex-wrap justify-center gap-6">
          {todayFoods.length === 0 && (
            <div className="text-center text-gray-500 text-lg w-full">
              No foods marked for today.
            </div>
          )}

          {todayFoods.map((food, index) => (
            <motion.div
              key={food._id}
              className="card w-50 md:w-64 hover:shadow-2xl transition-all"
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.97 }}
            >
              {food.img && (
                <motion.img
                  src={`/uploads/${food.img}`}
                  alt={food.name}
                  className="w-full h-40 object-cover rounded-t-2xl"
                  whileHover={{ scale: 1.05 }}
                  transition={{ duration: 0.3 }}
                />
              )}

              <div className="card-body">
                
                <div className="font-semibold text-lg text-slate-700">
                  {food.name}
                </div>
                <div className="text-sm text-gray-500 mb-3">₹{food.price}</div>

                <motion.button
                  className={`px-5 py-2 btn text-white text-sm font-medium rounded-full shadow ${
                    food.outofstack
                      ? "bg-gray-400 cursor-not-allowed"
                      : "bg-success hover:bg-green-600"
                  }`}
                  whileHover={!food.outofstack ? { scale: 1.05 } : {}}
                  whileTap={!food.outofstack ? { scale: 0.9 } : {}}
                  onClick={() => outOfStockEvent(food._id)}
                  disabled={food.outofstack}
                >
                  {food.outofstack ? "OUT-OF-STOCK" : "Mark Out-of-Stock"}
                </motion.button>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </div>
  );
}
